parameters.jsCode:
// Extract the framework selection from Anthropic response
const items = $input.all();
const response = items[0].json;

let frameworkSelection = null;

if (response.content && response.content[0]?.text) {
  const responseText = response.content[0].text.trim();

  try {
    // Parse the JSON response
    frameworkSelection = JSON.parse(responseText);
  } catch (parseError) {
    // If JSON parsing fails, try to extract JSON from markdown code blocks
    const jsonMatch = responseText.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (jsonMatch && jsonMatch[1]) {
      frameworkSelection = JSON.parse(jsonMatch[1].trim());
    } else {
      throw new Error('Failed to parse framework selection response as JSON');
    }
  }
} else {
  throw new Error('Invalid response from LLM');
}

// Validate the response structure
if (!frameworkSelection.selected_framework || !frameworkSelection.reasoning) {
  throw new Error('Invalid framework selection response structure');
}

// Get the original data
const webhookData = $node["Validate Input"].json;

return [
  {
    json: {
      prompt_run_id: webhookData.prompt_run_id,
      selected_framework: frameworkSelection.selected_framework,
      framework_reasoning: frameworkSelection.reasoning,
      task_characteristics: frameworkSelection.task_characteristics || {},
      alternative_frameworks: frameworkSelection.alternative_frameworks || [],
      model_used: response.model || 'claude-3-5-sonnet-20241022',
      tokens_used: (response.usage?.input_tokens || 0) + (response.usage?.output_tokens || 0)
    }
  }
];
